def add_competitor(name):
    session = get_db_session()

    new_competitor = Competitor(name=name, monitoring=True)
    session.add(new_competitor)
    session.commit()

def monitor_patents(competitor_name, patent_ids):
    session = get_db_session()

    competitor = session.query(Competitor).filter_by(name=competitor_name).first()
    if not competitor:
        raise ValueError(f"Competitor {competitor_name} does not exist.")

    for patent_id in patent_ids:
        patent = session.query(Patent).get(patent_id)
        if not patent:
            raise ValueError(f"Patent ID {patent_id} does not exist.")

        patent.competitor = True
        session.commit()
```

### 3. **Legal Status Monitoring**
Track legal status changes for monitored patents.

#### Example Code:
```python
def update_legal_status(patent_id, new_status):
    session = get_db_session()

    patent = session.query(Patent).get(patent_id)
    if not patent:
        raise ValueError(f"Patent ID {patent_id} does not exist.")

    patent.legal_status = new_status
    session.commit()

def check_legal_status_changes():
    session = get_db_session()

    monitored_patents = session.query(Patent).filter_by(competitor=True)

