        },
        {
            "entity_id": "entity_002",
            "name": "Apparatus X",
            "type": "apparatus",
            "claim_numbers": [3]
        }
    ]

    return jsonify({
        "patent_id": data["patent_id"],
        "parsed_entities": entities
    })

@app.route('/health', methods=['GET'])
def health():
    return jsonify({"status": "UP"})

