def score_infringement_likelihood(claim_element, doc_text):
    match_score = find_match_in_doc(claim_element, doc_text)

    if match_score:
        return 1.0  # Perfect match
    else:
        similarity_score = compute_similarity(claim_element, doc_text)
        return max(similarity_score, 0.3)  # Threshold to avoid zero scores

def find_match_in_doc(element, doc_text):
    match = re.search(re.escape(element), doc_text)
    if match:
        return 1.0
    return None

def compute_similarity(claim_element, doc_text):
    claim_embedding = embedding_model.encode([claim_element])
    doc_embedding = embedding_model.encode(doc_text)

    similarity_score = cosine_similarity(claim_embedding, doc_embedding).flatten()[0]
    return similarity_score
