def find_gaps_in_claim_chart(claim_chart):
    gaps = []

    for doc in claim_chart["prior_art_documents"]:
        for element in extract_elements(claim_chart["text"]):
            if not any(match['element'] == element for match in doc["matches"]):
                gaps.append(element)

    return gaps
