        function filterResults(threshold) {
            $.getJSON('/search', { query: 'Data processing apparatus' }, function(data) {
                renderFilteredResults(data.results, threshold);
            });
        }

        function renderResults(results) {
            $('#results').html(renderResultList(results));
        }

        function renderFilteredResults(results, threshold) {
            var filtered_results = results.filter(result => result.relevance_score >= threshold);
            $('#results').html(renderResultList(filtered_results));
        }

        function renderResultList(results) {
            return results.map(result => `
                <div class="result">
                    <h3>${result.title}</h3>
                    <p>Patent ID: ${result.patent_id}</p>
                    <p>Relevance Score: ${result.relevance_score.toFixed(2)}</p>
                </div>
            `).join('');
        }
    </script>
