    const threshold = parseFloat(document.getElementById('threshold').value);

    document.getElementById('prior_art_list').innerHTML = '';

    $.ajax({
        url: '/get_prior_art',
        method: 'POST',
        data: JSON.stringify({ patent_number: "US123456789" }),
        contentType: 'application/json',
        success: function(response) {
            const filteredDocs = response.filter(doc => doc.relevance_score >= threshold);
            displayPriorArtDocuments(filteredDocs);
        },
        error: function(error) {
            console.error('Error fetching prior art:', error);
        }
    });
}

function displayPriorArtDocuments(docs) {
    docs.forEach(doc => {
        document.getElementById('prior_art_list').innerHTML += `
            <div>
                <h3>${doc.title}</h3>
                <p>Relevance Score: ${doc.relevance_score.toFixed(2)}</p>
                <p>${doc.abstract}</p>
            </div>
        `;
    });
}
```

