from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/get_prior_art', methods=['POST'])
def get_prior_art():
    data = request.json
    patent_number = data.get('patent_number')

    # Fetch the target patent details (for demonstration purposes, assume it's already parsed)
    target_patent = extract_target_patent(patent_number)

    prior_art_docs = retrieve_prior_art(target_patent)

    ranked_prior_art_docs = sorted(prior_art_docs, key=lambda x: x['relevance_score'], reverse=True)

    return jsonify(ranked_prior_art_docs)

if __name__ == '__main__':
    app.run(port=5001, debug=True)
